import React from 'react';
import styled from 'styled-components';
import { useTheme } from '../context/ThemeContext';

const HeroSection = styled.section`
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: ${props => props.theme.background};
  position: relative;
  overflow: hidden;
  padding: 100px 20px;
  transition: all 0.3s ease;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(
      45deg,
      ${props => props.theme.primary}22,
      ${props => props.theme.secondary}22
    );
    z-index: 1;
  }
`;

const HeroContent = styled.div`
  max-width: 1200px;
  text-align: center;
  position: relative;
  z-index: 2;
`;

const Title = styled.h1`
  font-size: 4rem;
  color: ${props => props.theme.primary};
  margin-bottom: 1.5rem;
  transition: all 0.3s ease;
  text-shadow: 2px 2px 4px ${props => props.theme.shadowColor};

  @media (max-width: 768px) {
    font-size: 3rem;
  }
`;

const Subtitle = styled.p`
  font-size: 1.5rem;
  color: ${props => props.theme.text};
  margin-bottom: 2rem;
  max-width: 800px;
  margin-left: auto;
  margin-right: auto;
  line-height: 1.6;
  transition: all 0.3s ease;
`;

const CTAButton = styled.button`
  padding: 15px 40px;
  font-size: 1.1rem;
  background: ${props => props.theme.primary};
  color: ${props => props.theme.background};
  border: none;
  border-radius: 30px;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0 4px 15px ${props => props.theme.shadowColor};

  &:hover {
    background: ${props => props.theme.hoverColor};
    transform: translateY(-3px);
  }
`;

const Hero = () => {
  const { theme } = useTheme();

  return (
    <HeroSection theme={theme}>
      <HeroContent>
        <Title theme={theme}>Welcome to OPTIMUS</Title>
        <Subtitle theme={theme}>
          Innovating the future through technology and collaboration
        </Subtitle>
        <CTAButton theme={theme}>Join Us</CTAButton>
      </HeroContent>
    </HeroSection>
  );
};

export default Hero;
